import './index.css';

import {
  useState
} from 'react';

import {
  useNavigate
} from 'react-router-dom';

import {
  loginUser
} from '../../../services/authService';

function LoginForm() {

  const navigate =
    useNavigate();

  const [formData, setFormData] =
    useState({
      email: '',
      password: ''
    });

  const handleChange =
    (e) => {

    setFormData({
      ...formData,
      [e.target.name]:
      e.target.value
    });

  };

  const handleSubmit =
    async (e) => {

    e.preventDefault();

    try {

      const data =
        await loginUser(formData);

      localStorage.setItem(
        'token',
        data.token
      );

      navigate(
        '/teacher-dashboard'
      );

    } catch (error) {

      alert(
        error.response?.data?.message
      );

    }

  };

  return (

    <form
      className="login-form"
      onSubmit={handleSubmit}
    >

      <h2>Teacher Login</h2>

      <input
        type="email"
        name="email"
        placeholder="Email"
        onChange={handleChange}
      />

      <input
        type="password"
        name="password"
        placeholder="Password"
        onChange={handleChange}
      />

      <button type="submit">
        Login
      </button>

    </form>

  );

}

export default LoginForm;
